42	/*
43	 * njs_opaque_value_t is the external storage type for native njs_value_t type.
44	 * sizeof(njs_opaque_value_t) == sizeof(njs_value_t).
45	 */
46	
47	typedef struct {
48	    uint32_t                        filler[4];
49	} njs_opaque_value_t;
