51	/* sizeof(njs_value_t) is 16 bytes. */
52	#define njs_argument(args, n)                                                 \
53	    (njs_value_t *) ((u_char *) args + (n) * 16)
54	
55	
56	extern const njs_value_t            njs_value_undefined;
57	
58	#define njs_arg(args, nargs, n)                                               \
59	    ((n < nargs) ? njs_argument(args, n)                                      \
60	                 : (njs_value_t *) &njs_value_undefined)
61	
62	#define njs_value_assign(dst, src)                                            \
63	    memcpy(dst, src, sizeof(njs_opaque_value_t))
64	
65	#define njs_value_arg(val) ((njs_value_t *) val)
66	#define njs_value_atom(val) (((njs_opaque_value_t *) (val))->filler[0])
67	
68	#define njs_atom_is_number(atom_id) ((atom_id) & 0x80000000)
69	#define njs_atom_number(atom_id) ((atom_id) & 0x7FFFFFFF)
70	#define njs_number_atom(n) ((n) | 0x80000000)
71	
72	#define njs_lvalue_arg(lvalue, args, nargs, n)                                \
73	    ((n < nargs) ? njs_argument(args, n)                                      \
74	                 : (njs_value_assign(lvalue, &njs_value_undefined), lvalue))
