89	#define njs_deprecated(vm, text)                                             \
90	    do {                                                                     \
91	        static njs_bool_t  reported;                                         \
92	                                                                             \
93	        if (!reported) {                                                     \
94	            njs_vm_warn(vm, text " is deprecated "                           \
95	                        "and will be removed in the future");                \
96	            reported = 1;                                                    \
97	        }                                                                    \
98	    } while(0)
