261	/*
262	 * interactive  - enables "interactive" mode.
263	 *  (REPL). Allows starting parent VM without cloning.
264	 * disassemble   - enables disassemble.
265	 * backtrace     - enables backtraces.
266	 * quiet         - removes filenames from backtraces. To produce comparable
267	    test262 diffs.
268	 * sandbox       - "sandbox" mode. Disables file access.
269	 * unsafe        - enables unsafe language features:
270	 *   - Function constructors.
271	 * module        - ES6 "module" mode. Script mode is default.
272	 * ast           - print AST.
273	 */
274	    uint8_t                         interactive;     /* 1 bit */
275	    uint8_t                         trailer;         /* 1 bit */
276	    uint8_t                         init;            /* 1 bit */
277	    uint8_t                         disassemble;     /* 1 bit */
278	    uint8_t                         backtrace;       /* 1 bit */
279	    uint8_t                         quiet;           /* 1 bit */
280	    uint8_t                         sandbox;         /* 1 bit */
281	    uint8_t                         unsafe;          /* 1 bit */
282	    uint8_t                         module;          /* 1 bit */
283	    uint8_t                         ast;             /* 1 bit */
284	#ifdef NJS_DEBUG_OPCODE
285	    uint8_t                         opcode_debug;    /* 1 bit */
286	#endif
287	#ifdef NJS_DEBUG_GENERATOR
